// SNAC 44kHz encoder, real-time variant. There is no incremental/cached
// conv-state ONNX graph for SNAC (unlike EnCodec's LSTM h/c) -- the same
// encode_audio_segment.onnx the buffer module uses always runs its whole
// conv stack fresh on whatever's handed to it. So "streaming" here means
// windowed context-trim: each new kBlockSize-sample block is prepended
// with the PREVIOUS block (kContextSize == kBlockSize, one block of real
// trailing audio) before Run(), and only the newly-computed frames
// (covering just the new block) are kept -- the leading, context-derived
// frames are discarded every time. This needs no changes to the
// exported ONNX graph and reuses the exact weights/graph already
// validated in the buffer module; the cost is discarding half the
// compute (context frames) every block, and a latency floor of one block
// (kBlockSize samples @ 44kHz) before the first embeddings can appear.
// Identical network to snac_32kh (only sampling rate and weights
// differ) -- see ncs.rt.snac_24kh.encode_tilde.cpp for the full design
// rationale this module mirrors.
//
// kBlockSize is chosen as one preprocess_pad multiple (12288 samples ==
// hop_length(384) * lcm(vq_strides[0]=8, attn_window_size=32) = 384*32,
// matching ncs.snac_44kh.encode's padding rule) so every block's frame
// count stays aligned with BOTH the VQ stride grouping and the local
// attention window without needing extra padding logic here. This is a
// much bigger block (and latency floor) than snac_24kh's 2048 samples --
// 32k/44k's local attention (window=32) combined with a coarsest VQ
// stride of 8 forces a much larger minimum granularity than 24k's
// conv-only, no-attention architecture.
static constexpr int64_t kHopLength    = 384;
static constexpr int64_t kBlockFrames  = 32;                         // frames per block (== attn_window_size)
static constexpr int64_t kBlockSize    = kHopLength * kBlockFrames;  // 12288 samples
static constexpr int64_t kContextSize  = kBlockSize;                 // one block of trailing context
static constexpr int64_t kLatentDim    = 1024;

// Each block's trimmed output is kLatentDim*kBlockFrames = 32768 floats
// -- a single unchunked Max list message that size is well past the
// crash threshold documented in ncs.snac_24kh.encode.cpp (~15k-20k atoms
// confirmed to crash Max's own outlet_cache/real_outlet_list via a raw
// memmove overflow). snac_24kh's rt~ block (768*4=3072 atoms) never hit
// this and so never needed chunking, but 32k/44k's much larger block
// (32x the frames, 1024 vs 768 channels) does. So data_out here sends
// the SAME messageix/tensor chunked protocol the buffer modules use,
// and ncs.rt.snac_44kh.vq reassembles it -- unlike snac_24kh.rt's plain
// "list" transport.
//
// kMaxChunkAtoms is 12000 here (vs the buffer modules' 4000) -- still a
// comfortable margin below the ~15.4k confirmed-safe / ~15k-20k crash
// zone, but this is a CONTINUOUS real-time stream (a new block every
// kBlockSize/kModelSampleRate seconds, forever), unlike buffer mode's
// occasional bang. flush_output() sends at most one message per 10ms
// timer tick; at 4000 this block took 9 chunks x 2 messages = 18 ticks
// (~180ms) just to relay through THIS one hop, stacking with the same
// cost on ncs.rt.snac_44kh.embedcodes -> ncs.rt.snac_44kh.decode~'s hop
// and the model's own ~279ms block-latency floor -- enough added
// serialization delay to starve decode~'s ring buffer and cause audible
// dropouts. 12000 cuts this to 3 chunks x 2 = 6 ticks (~60ms).
static constexpr size_t kMaxChunkAtoms = 12000;

// The model only works at 44kHz; the live host DSP rate is whatever
// Max's signal chain is running at. Unlike the buffer module's one-shot
// src_simple() call, this runs continuously block after block, so the
// resampler here must carry its filter state across calls (see
// ncs_resample::StreamingResampler) or every block boundary would click.
static constexpr double kModelSampleRate = 44100.0;

// Granularity (in HOST-rate samples) at which incoming audio is handed
// to the streaming resampler -- independent of Max's DSP vector size, so
// behavior doesn't change if the user changes their signal vector size.
static constexpr size_t kHostFlushSamples = 256;

